1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type ScenarioInput = {
3	  customer: { yearsWithMHPCO: number };
4	  steps: { items: Item[] }[];
5	};
6	
7	const PROCESSING_FEE = 5;
8	const CURSE_SURCHARGE_RATE = 0.5;
9	const HIGH_ENCHANTMENT_RATE = 0.3;
10	const HIGH_ENCHANTMENT_THRESHOLD = 5;
11	const LOYALTY_DISCOUNT_RATE = 0.2;
12	const LOYALTY_YEARS_THRESHOLD = 2;
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const COMPONENT_BASE = 25;
15	const COMPONENT_BLOCK_BASE = 60;
16	const COMPONENT_BLOCK_SIZE = 3;
17	const ITEM_BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	
24	function policyBase(items: Item[]): number {
25	  const components: Record<string, number> = {};
26	  let base = 0;
27	  for (const item of items) {
28	    if (COMPONENT_TYPES.has(item.type)) {
29	      components[item.type] = (components[item.type] ?? 0) + 1;
30	    } else {
31	      base += ITEM_BASE_PREMIUM[item.type];
32	    }
33	  }
34	  for (const count of Object.values(components)) {
35	    base += count === COMPONENT_BLOCK_SIZE
36	      ? COMPONENT_BLOCK_BASE
37	      : count * COMPONENT_BASE;
38	  }
39	  return base;
40	}
41	
42	function surchargeOn(
43	  items: Item[],
44	  rate: number,
45	  applies: (item: Item) => boolean,
46	): number {
47	  let total = 0;
48	  for (const item of items) {
49	    if (applies(item)) {
50	      total += ITEM_BASE_PREMIUM[item.type] * rate;
51	    }
52	  }
53	  return total;
54	}
55	
56	const isCursed = (item: Item): boolean => item.cursed === true;
57	const isHighlyEnchanted = (item: Item): boolean =>
58	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
59	
60	export function runScenario(input: unknown): unknown {
61	  const { customer, steps: [{ items }] } = input as ScenarioInput;
62	  const base = policyBase(items);
63	  // First-insurance is +10% on the base; use integer tenths to avoid float drift.
64	  const withFirstInsurance = (base * 11) / 10;
65	  const curse = surchargeOn(items, CURSE_SURCHARGE_RATE, isCursed);
66	  const highEnch = surchargeOn(items, HIGH_ENCHANTMENT_RATE, isHighlyEnchanted);
67	  const loyalty = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
68	    ? base * LOYALTY_DISCOUNT_RATE
69	    : 0;
70	  const premium = Math.ceil(withFirstInsurance + curse + highEnch - loyalty) + PROCESSING_FEE;
71	  return { results: [{ premium }] };
72	}
